-- PDI/PDP — Fase 0: camada de catálogo (aditivo; não altera tabelas existentes)
-- Fonte: PDP 2026 V3 (DNA pág.8, régua pág.4/Anexo3, QCRJ pág.16, matriz skills págs.17-20)

CREATE TABLE IF NOT EXISTS people.pdi_carreiras (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL,
  codigo varchar NOT NULL, nome varchar NOT NULL, ordem int, ativo boolean NOT NULL DEFAULT true,
  UNIQUE (tenant_id, codigo));

CREATE TABLE IF NOT EXISTS people.pdi_faixas_avaliacao (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL,
  codigo varchar NOT NULL, rotulo varchar NOT NULL, ordem int NOT NULL,
  progride boolean NOT NULL DEFAULT false, bonus_pdi boolean NOT NULL DEFAULT false,
  plr_plus_elegivel boolean NOT NULL DEFAULT false, reflexo text,
  UNIQUE (tenant_id, codigo));

CREATE TABLE IF NOT EXISTS people.pdi_pilares (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL,
  trilha varchar NOT NULL, numero int NOT NULL, nome varchar NOT NULL,
  UNIQUE (tenant_id, trilha, numero));

CREATE TABLE IF NOT EXISTS people.pdi_dna_itens (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL,
  numero int NOT NULL, nome varchar NOT NULL, descricao text,
  UNIQUE (tenant_id, numero));

CREATE TABLE IF NOT EXISTS people.pdi_skills_catalogo (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL,
  trilha varchar NOT NULL, pilar_numero int NOT NULL, nivel_codigo varchar NOT NULL,
  item_codigo varchar NOT NULL DEFAULT '', titulo varchar, descricao text, ordem int,
  UNIQUE (tenant_id, trilha, pilar_numero, nivel_codigo, item_codigo));

CREATE TABLE IF NOT EXISTS people.pdi_quadro_remuneracao (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL,
  carreira_codigo varchar NOT NULL, cargo_codigo varchar NOT NULL, coluna varchar NOT NULL,
  salario numeric(12,2), observacao text,
  UNIQUE (tenant_id, carreira_codigo, cargo_codigo, coluna));







CREATE OR REPLACE FUNCTION public.get_pdi_catalogo()
RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, people, core AS $function$
DECLARE v_tenant uuid;
BEGIN
  SELECT tenant_id INTO v_tenant FROM core.tenant_users WHERE user_id = auth.uid() AND status = 'ativo' LIMIT 1;
  IF v_tenant IS NULL THEN RAISE EXCEPTION 'Usuário não associado a tenant'; END IF;
  RETURN jsonb_build_object(
    'carreiras', (SELECT COALESCE(jsonb_agg(to_jsonb(c) ORDER BY c.ordem),'[]'::jsonb) FROM people.pdi_carreiras c WHERE c.tenant_id=v_tenant AND c.ativo),
    'regua', (SELECT COALESCE(jsonb_agg(to_jsonb(f) ORDER BY f.ordem),'[]'::jsonb) FROM people.pdi_faixas_avaliacao f WHERE f.tenant_id=v_tenant),
    'pilares', (SELECT COALESCE(jsonb_agg(to_jsonb(p) ORDER BY p.trilha,p.numero),'[]'::jsonb) FROM people.pdi_pilares p WHERE p.tenant_id=v_tenant),
    'dna', (SELECT COALESCE(jsonb_agg(to_jsonb(d) ORDER BY d.numero),'[]'::jsonb) FROM people.pdi_dna_itens d WHERE d.tenant_id=v_tenant),
    'skills', (SELECT COALESCE(jsonb_agg(to_jsonb(s) ORDER BY s.trilha,s.pilar_numero,s.nivel_codigo,s.item_codigo),'[]'::jsonb) FROM people.pdi_skills_catalogo s WHERE s.tenant_id=v_tenant),
    'quadro_remuneracao', (SELECT COALESCE(jsonb_agg(to_jsonb(q) ORDER BY q.carreira_codigo,q.cargo_codigo,q.coluna),'[]'::jsonb) FROM people.pdi_quadro_remuneracao q WHERE q.tenant_id=v_tenant)
  );
END;
$function$;
GRANT EXECUTE ON FUNCTION public.get_pdi_catalogo() TO authenticated;
